"use client";

import { Button } from "@heroui/button";
import { Moon02Icon, Sun03Icon, SunriseIcon, SunsetIcon } from "@icons";
import type { FC } from "react";
import type { TimeOfDay } from "@/features/landing/utils/timeOfDay";

type IconComponent = FC<{ width: number; height: number }>;

const TOD_ICON: Record<TimeOfDay, IconComponent> = {
  morning: SunriseIcon,
  day: Sun03Icon,
  evening: SunsetIcon,
  night: Moon02Icon,
};

interface TimeOfDayToggleProps {
  timeOfDay: TimeOfDay;
  isDark: boolean;
  onPress: () => void;
}

export function TimeOfDayToggle({
  timeOfDay,
  isDark,
  onPress,
}: TimeOfDayToggleProps) {
  const Icon = TOD_ICON[timeOfDay];
  return (
    <Button
      isIconOnly
      variant="flat"
      size="sm"
      onPress={onPress}
      aria-label={`Switch time of day, currently ${timeOfDay}`}
      className={`opacity-40 hover:opacity-85 transition-opacity ${isDark ? "text-white" : "text-black"}`}
    >
      <Icon width={17} height={17} />
    </Button>
  );
}

